changeSet.sql:
ALTER TABLE role_permissions
    ADD COLUMN IF NOT EXISTS created_at TIMESTAMP WITHOUT TIME ZONE;
ALTER TABLE role_permissions
    ADD COLUMN IF NOT EXISTS created_by_id BIGINT;
ALTER TABLE role_permissions
    ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP WITHOUT TIME ZONE;
ALTER TABLE role_permissions
    ADD COLUMN IF NOT EXISTS updated_by_id BIGINT;
ALTER TABLE role_permissions
    ADD COLUMN IF NOT EXISTS version BIGINT DEFAULT 0;

UPDATE role_permissions
SET version = 0
WHERE version IS NULL;

CREATE INDEX IF NOT EXISTS idx_role_permissions_created_by_id
    ON role_permissions (created_by_id);
CREATE INDEX IF NOT EXISTS idx_role_permissions_updated_by_id
    ON role_permissions (updated_by_id);
